('00000000-0000-4000-a000-000000000005', '2k-12-week', '2K 12-Week Build', 'Twelve weeks of progressive overload to improve your 2K erg time. Two cycles of increasing volume and intensity, bookended by 2K tests to measure improvement.', 'advanced', 12, 3, '{2k-12-week,advanced,progressive-overload}', '[{"week_number":1,"title":"Baseline","sessions":[{"day_label":"Day 1","workout_id":"a0000000-0000-0000-0000-000000000001","notes":"2K time trial — establish your baseline"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0001-000000000001","notes":"4x4min threshold intervals"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0001-000000000002","notes":"6x2min speed work"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000001","notes":"5K steady state for extra volume"}]},{"week_number":2,"title":"Build Volume","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0001-000000000001","notes":"4x4min threshold intervals"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0002-000000000001","notes":"3x6min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0001-000000000002","notes":"6x2min speed work"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000001","notes":"5K steady state for extra volume"}]},{"week_number":3,"title":"Progression","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0003-000000000001","notes":"5x4min threshold — more volume"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0002-000000000001","notes":"3x6min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0003-000000000002","notes":"8x2min speed — maintain pace from week 1"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000002","notes":"6K steady state for extra volume"}]},{"week_number":4,"title":"Peak Cycle 1","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0003-000000000001","notes":"5x4min threshold — push pace"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0002-000000000001","notes":"3x6min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0003-000000000002","notes":"8x2min speed work"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000002","notes":"6K steady state for extra volume"}]},{"week_number":5,"title":"Cycle 2","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0005-000000000001","notes":"6x4min threshold — higher volume"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0005-000000000002","notes":"4x6min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0005-000000000003","notes":"10x2min speed work"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000003","notes":"8K steady state for extra volume"}]},{"week_number":6,"title":"Build","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0005-000000000001","notes":"6x4min — improve pace from last week"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0005-000000000002","notes":"4x6min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0005-000000000003","notes":"10x2min speed work"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000003","notes":"8K steady state for extra volume"}]},{"week_number":7,"title":"Sharpen","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0007-000000000001","notes":"6x3min — shorter, harder efforts"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0007-000000000002","notes":"4x5min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0007-000000000003","notes":"12x1min speed bursts"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000004","notes":"10K steady state for extra volume"}]},{"week_number":8,"title":"Test Week","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0008-000000000001","notes":"6x2min taper — stay sharp"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0008-000000000002","notes":"4x4min taper — easy pace"},{"day_label":"Day 3","workout_id":"a0000000-0000-0000-0000-000000000001","notes":"2K test — give it everything!"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000004","notes":"10K easy if you have energy"}]},{"week_number":9,"title":"Cycle 2 Repeat","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0005-000000000001","notes":"6x4min threshold — beat your week 5 pace"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0005-000000000002","notes":"4x6min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0005-000000000003","notes":"10x2min speed work"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000003","notes":"8K steady state for extra volume"}]},{"week_number":10,"title":"Build Again","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0005-000000000001","notes":"6x4min — improve pace from last week"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0005-000000000002","notes":"4x6min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0005-000000000003","notes":"10x2min speed work"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000003","notes":"8K steady state for extra volume"}]},{"week_number":11,"title":"Final Sharpen","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0007-000000000001","notes":"6x3min — shorter, harder efforts"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0007-000000000002","notes":"4x5min tempo work"},{"day_label":"Day 3","workout_id":"f2000000-0000-0000-0007-000000000003","notes":"12x1min speed bursts"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000004","notes":"10K steady state for extra volume"}]},{"week_number":12,"title":"Final Test","sessions":[{"day_label":"Day 1","workout_id":"f2000000-0000-0000-0008-000000000001","notes":"6x2min taper — stay sharp"},{"day_label":"Day 2","workout_id":"f2000000-0000-0000-0008-000000000002","notes":"4x4min taper — easy pace"},{"day_label":"Day 3","workout_id":"a0000000-0000-0000-0000-000000000001","notes":"2K test — beat your week 8 time!"},{"day_label":"Day 4 (Optional)","workout_id":"f2000000-0000-0000-000d-000000000004","notes":"10K easy if you have energy"}]}]'::jsonb)
