00000002","notes":"VO2max intervals"},{"day_label":"Day 3","workout_id":"e1000000-0000-0000-0005-000000000003","notes":"Steady state recovery"}]},{"week_number":6,"title":"Taper","sessions":[{"day_label":"Day 1","workout_id":"e1000000-0000-0000-0006-000000000001","notes":"Easy recovery"},{"day_label":"Day 2","workout_id":"e1000000-0000-0000-0006-000000000002","notes":"Light steady state"},{"day_label":"Day 3","workout_id":"e1000000-0000-0000-0006-000000000003","notes":"Openers — short efforts to stay sharp"}]}]'::jsonb)
