750m intervals"},{"day_label":"Day 3","workout_id":"e0000000-0000-0000-0003-000000000004","notes":"22 min steady state"}]},{"week_number":6,"title":"Consolidation","sessions":[{"day_label":"Day 1","workout_id":"e0000000-0000-0000-0001-000000000005","notes":"7500m steady distance"},{"day_label":"Day 2","workout_id":"e0000000-0000-0000-0002-000000000005","notes":"4x1000m intervals"},{"day_label":"Day 3","workout_id":"e0000000-0000-0000-0003-000000000005","notes":"24 min steady state"}]}]'::jsonb)
